/* ── CASE CAROUSEL ── */
function CaseCarousel({ setPage }) {
  const [idx, setIdx] = useState(0);
  const max = CASES.length - 2;
  const timerRef = useRef(null);
  const next = () => setIdx(i => i >= max ? 0 : i + 1);
  useEffect(() => { timerRef.current = setInterval(next, 4200); return () => clearInterval(timerRef.current); }, [idx]);
  const manual = (i) => { clearInterval(timerRef.current); setIdx(Math.max(0,Math.min(max,i))); timerRef.current = setInterval(next, 4200); };
  return (
    <div className="cases-section">
      <div className="cases-header reveal">
        <h2>Case Studies</h2>
        <div className="ctrls">
          <button className="ctrl" onClick={()=>manual(idx<=0?max:idx-1)}>←</button>
          <button className="ctrl" onClick={()=>manual(idx>=max?0:idx+1)}>→</button>
        </div>
      </div>
      <div className="cases-outer">
        <div className="cases-track" style={{transform:`translateX(calc(-${idx*50}% - ${idx*.75}rem))`}}>
          {CASES.map(c => (
            <div key={c.slug} className="case-card" onClick={()=>setPage("case:"+c.slug)}>
              <img src={c.img} alt={c.name} />
              <div className="case-body">
                <div className="case-cat">{c.cat}</div>
                <div className="case-name">{c.name}</div>
                <div className="case-desc">{c.desc}</div>
                <button className="case-btn" onClick={e=>{e.stopPropagation();setPage("case:"+c.slug);}}>See Case Study</button>
              </div>
            </div>
          ))}
        </div>
      </div>
      <div style={{display:"flex",gap:".5rem",justifyContent:"center",marginTop:"1.2rem"}}>
        {Array.from({length:max+1}).map((_,i)=>(
          <button key={i} onClick={()=>manual(i)} style={{width:i===idx?"26px":"8px",height:"8px",borderRadius:"4px",border:"none",background:i===idx?"#0D1B2E":"rgba(13,27,46,.18)",cursor:"pointer",transition:"all .35s",padding:0}}/>
        ))}
      </div>
    </div>
  );
}

/* ── SIMPLE CHART ── */
function SimpleChart({ config }) {
  if (!config) return null;
  const { type, title, labels, data } = config;
  const W=420, H=220, pad={t:20,r:20,b:50,l:48};
  const cW = W-pad.l-pad.r, cH = H-pad.t-pad.b;
  const max = Math.max(...data)*1.15;
  const min = type==="bar" ? 0 : Math.min(...data)*0.85;
  const range = max - min;
  const toY = v => pad.t + cH - ((v-min)/range)*cH;
  const toX = (i,n) => pad.l + (i/(n-1))*cW;
  const ticks = 5;

  if (type==="line") {
    const pts = data.map((v,i)=>({x:toX(i,data.length),y:toY(v)}));
    const d = pts.map((p,i)=>`${i===0?"M":"L"}${p.x},${p.y}`).join(" ");
    return (
      <div className="cs-chart-wrap">
        <div className="cs-chart-title">{title}</div>
        <svg viewBox={`0 0 ${W} ${H}`} className="chart-svg">
          {Array.from({length:ticks+1}).map((_,i)=>{
            const v = min+(range/ticks)*i;
            const y = toY(v);
            return <g key={i}><line x1={pad.l} x2={W-pad.r} y1={y} y2={y} className="chart-grid"/><text x={pad.l-6} y={y+4} textAnchor="end" className="chart-val">{Math.round(v)}</text></g>;
          })}
          <path d={d} className="chart-line"/>
          {pts.map((p,i)=><circle key={i} cx={p.x} cy={p.y} r={4} className="chart-dot"/>)}
          {labels.map((l,i)=><text key={i} x={toX(i,labels.length)} y={H-10} textAnchor="middle" className="chart-label">{l}</text>)}
        </svg>
      </div>
    );
  }
  const barW = cW/(data.length*2.2);
  return (
    <div className="cs-chart-wrap">
      <div className="cs-chart-title">{title}</div>
      <svg viewBox={`0 0 ${W} ${H}`} className="chart-svg">
        {Array.from({length:ticks+1}).map((_,i)=>{
          const v = (max/ticks)*i;
          const y = toY(v);
          return <g key={i}><line x1={pad.l} x2={W-pad.r} y1={y} y2={y} className="chart-grid"/><text x={pad.l-6} y={y+4} textAnchor="end" className="chart-val">{Math.round(v)}</text></g>;
        })}
        {data.map((v,i)=>{
          const x = pad.l+(i/(data.length))*(cW)+(cW/(data.length)-barW)/2;
          const bH = ((v-0)/max)*cH;
          const y = pad.t+cH-bH;
          return <rect key={i} x={x} y={y} width={barW} height={bH} className="chart-bar" rx="3"/>;
        })}
        {labels.map((l,i)=>{
          const x = pad.l+(i/(data.length))*(cW)+(cW/(data.length))/2;
          return <text key={i} x={x} y={H-10} textAnchor="middle" className="chart-label">{l}</text>;
        })}
      </svg>
    </div>
  );
}

