/* ── CASE STUDY PAGE ── */
function HelpedItem({ item }) {
  if (item.bullet) {
    return <li>{item.text||""}{item.bold?<strong>{item.bold}</strong>:null}{item.after||""}</li>;
  }
  if (item.bold && item.text) return <li><strong>{item.bold}</strong>{item.text}</li>;
  return <li style={{listStyle:"none",paddingLeft:0,marginBottom:".4rem"}}>{item.text||""}</li>;
}

function ImpactItem({ item }) {
  return <li>{item.bold?<strong>{item.bold}</strong>:null}{item.text?" "+item.text:""}{item.after||""}</li>;
}

